const fs = require('fs');

function ArrayToObject(arr) {
  const result = {};
  arr.forEach(pair => {
    result[pair[0]] = pair[1];
  });
  return result;
}

const input = [['Country', 'India'], ['State', 'Gujarat'], ['City', 'Ahmedabad']];
