An **EventEmitter** in Node.js is a class from the built-in 'events' module that enables objects to emit named events and register listener functions that respond to those events.

**Key Concepts:**
- `.on(eventName, listener)`: Registers a listener for an event
- `.emit(eventName, [...args])`: Fires/triggers the named event
- `.removeListener(eventName, listener)`: Removes a specific listener
- `.listenerCount(eventName)`: Returns number of listeners for an event

**Example:**
```javascript
const events = require('events');
const ee = new events.EventEmitter();

ee.on('data', (msg) => {
  console.log('Received:', msg);
});

ee.emit('data', 'Hello Node.js!');
// Output: Received: Hello Node.js!
```

EventEmitter is the backbone of Node.js's event-driven architecture. Core modules like fs, http, and streams are all built on top of EventEmitter.

const events = require('events');

// Create EventEmitter instance
const myEmitter = new events.EventEmitter();

// Register callback 1
myEmitter.on('welcome', () => {
  console.log('Callback 1: Welcome to Node.js Events!');
});

// Register callback 2
myEmitter.on('welcome', (name) => {
  console.log(`Callback 2: Hello, ${name}!`);
});

// Register a one-time callback
myEmitter.once('start', () => {
  console.log('Start event fired once!');
});

// Emit events
myEmitter.emit('welcome', 'Dixit');
myEmitter.emit('start');
myEmitter.emit('start'); // This will NOT trigger the once callback again

const events = require('events');
const ee = new events.EventEmitter();

// 1. on() - register a persistent listener
ee.on('msg', (data) => { console.log('on() triggered:', data); });

// 2. once() - register a one-time listener
ee.once('login', () => { console.log('once() triggered: user logged in'); });

// 3. emit() - fire an event
ee.emit('msg', 'Hello World');   // triggers on()
ee.emit('login');                 // triggers once()
ee.emit('login');                 // does NOT trigger again

// 4. listenerCount() - count listeners for an event
console.log('Listener count for msg:', ee.listenerCount('msg'));

// 5. eventNames() - list all registered events
console.log('Event names:', ee.eventNames());

// 6. removeListener() / off() - remove a specific listener
const handler = () => console.log('handler');
ee.on('test', handler);
ee.removeListener('test', handler);
ee.emit('test'); // nothing prints

// 7. removeAllListeners() - remove all listeners for an event
ee.removeAllListeners('msg');
console.log('After removeAll, count:', ee.listenerCount('msg')); // 0

// 8. prependListener() - add listener to the beginning
ee.on('order', () => console.log('Second'));
ee.prependListener('order', () => console.log('First'));
ee.emit('order'); // prints First, then Second

const events = require('events');
const ee = new events.EventEmitter();

const marks = [22, 19, 24, 20, 18]; // 5 subjects, out of 25 each

// Percentage event handler
ee.on('percentage', (total) => {
  const maxMarks = 5 * 25;
  const percent = (total / maxMarks) * 100;
  console.log(`Percentage: ${percent.toFixed(2)}%`);
});

// Calculate event handler
ee.on('calculate', () => {
  const total = marks.reduce((sum, m) => sum + m, 0);
  console.log(`Total Marks: ${total} / ${5 * 25}`);
  ee.emit('percentage', total); // fire percentage event
});

// Fire calculate event
ee.emit('calculate');

const events = require('events');
const fs = require('fs');
const http = require('http');

const ee = new events.EventEmitter();
let fileContent = '';

// Event: write
ee.on('write', () => {
  fs.writeFile('abc.txt', 'Hello from Node.js Events!', (err) => {
    if (err) return console.error(err);
    console.log('File created.');
    ee.emit('append');
  });
});

// Event: append
ee.on('append', () => {
  fs.appendFile('abc.txt', '\nAppended line.', (err) => {
    if (err) return console.error(err);
    console.log('Data Appended Successfully');
    ee.emit('readFile');
  });
});

// Event: readFile
ee.on('readFile', () => {
  fs.readFile('abc.txt', 'utf-8', (err, data) => {
    if (err) return console.error(err);
    fileContent = data;
    ee.emit('serve');
  });
});

// Event: serve
ee.on('serve', () => {
  const server = http.createServer((req, res) => {
    res.writeHead(200, { 'Content-Type': 'text/plain' });
    res.end(fileContent);
  });
  server.listen(3000, () => {
    console.log('Server running at http://localhost:3000');
    console.log('All operations performed successfully');
  });
});

