// Basic routing uses req.url to check which page the client requested.
// Based on the URL path, different HTML responses are sent back.

const http = require('http');
const url = require('url');

const server = http.createServer((req, res) => {
  const parsed = url.parse(req.url, true); // true enables query parsing
  const query = parsed.query;

  res.writeHead(200, { 'Content-Type': 'text/html' });

  let output = '<h2>Query Parameters</h2>';
  for (const key in query) {
    output += `<p><b>${key}</b>: ${query[key]}</p>`;
  }

  res.end(output);
});

