/**
 * REQUEST OBJECT (req):
 * Contains information about the client's request:
 * - req.url: the URL path requested (e.g., '/about')
 * - req.method: HTTP method (GET, POST, etc.)
 * - req.headers: request headers sent by client
 * 
 * RESPONSE OBJECT (res):
 * Used to send data back to the client:
 * - res.writeHead(statusCode, headers): sets status and headers
 * - res.write(data): writes partial data to response
 * - res.end([data]): finalizes and sends the response
 * - res.setHeader(name, value): sets a single header
 */

const http = require('http');

http.createServer((req, res) => {
  res.writeHead(200, { 'Content-Type': 'text/html' });

  // res.write() can be called multiple times
  res.write('<h1>Hello from Node.js!</h1>');
  res.write('<p>This is sent using res.write()</p>');

  // res.end() must be called to complete the response
  res.end('<p>This final line is sent by res.end()</p>');

}).listen(3000);

