/**
 * Middleware in Express.js
 * A middleware function takes (req, res, next) as arguments.
 * It can execute code, modify req/res, end the request, or call next().
 */

const express = require('express');
const app = express();

// 1. Application-level middleware (runs on every request)
const logger = (req, res, next) => {
  console.log(`[${new Date().toISOString()}] ${req.method} ${req.url}`);
  next(); // pass to next middleware or route
};
app.use(logger);

// 2. Route-specific middleware
const checkAuth = (req, res, next) => {
  const token = req.headers['authorization'];
  if (token === 'LJU-SECRET') {
    next();
  } else {
    res.status(401).send('Unauthorized');
  }
};

app.get('/secure', checkAuth, (req, res) => {
  res.send('Welcome to secure route!');
});

