const express = require('express');
const app = express();

// Sample data
const students = [
  { id: 1, name: 'Alice', branch: 'CSE', marks: 85 },
  { id: 2, name: 'Bob', branch: 'IT', marks: 72 },
  { id: 3, name: 'Charlie', branch: 'CSE', marks: 91 },
  { id: 4, name: 'Diana', branch: 'CE', marks: 68 }
];

// GET all students with optional filtering
// Usage: /students?branch=CSE&minMarks=80
app.get('/students', (req, res) => {
  let result = students;

  // Filter by branch
  if (req.query.branch) {
    result = result.filter(s => s.branch === req.query.branch);
  }

  // Filter by minimum marks
  if (req.query.minMarks) {
    result = result.filter(s => s.marks >= parseInt(req.query.minMarks));
  }

  // Search by name (partial match)
  if (req.query.search) {
    result = result.filter(s => s.name.toLowerCase().includes(req.query.search.toLowerCase()));
  }

  res.json(result);
});

// GET student by ID
app.get('/students/:id', (req, res) => {
  const student = students.find(s => s.id === parseInt(req.params.id));
  if (!student) return res.status(404).json({ error: 'Student not found' });
  res.json(student);
});

