app.post('/calc', (req, res) => {
  const { num1, num2, formula } = req.body;
  const n1 = parseFloat(num1);
  const n2 = parseFloat(num2);

  if (n1 <= 0 || n2 <= 0) {
    return res.send("<p>Please enter the valid number</p>");
  }
  if (!formula) {
    return res.send("<p>You have not selected any formula</p>");
  }

  res.cookie('num1', n1, { maxAge: 50000 });
  res.cookie('num2', n2, { maxAge: 50000 });

  let result;
  if (formula === 'addition') result = n1 + n2;
  else if (formula === 'subtraction') result = n1 - n2;
  else if (formula === 'multiplication') result = n1 * n2;
  else if (formula === 'division') result = n2 !== 0 ? n1 / n2 : 'Cannot divide by zero';

  res.send(`<h2>${formula}: ${result}</h2>`);
});

