const express = require('express');
const multer = require('multer');
const sharp = require('sharp');
const path = require('path');
const fs = require('fs');
const app = express();

// Use memory storage (sharp will handle saving)
const upload = multer({ storage: multer.memoryStorage() });

// Ensure output directories exist
['uploads/small', 'uploads/medium', 'uploads/large'].forEach(dir => {
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
});

app.get('/', (req, res) => {
  res.send(`
    <form action="/upload" method="post" enctype="multipart/form-data">
      <input type="file" name="image" accept="image/*" />
      <button type="submit">Upload and Resize</button>
    </form>
  `);
});

app.post('/upload', upload.single('image'), async (req, res) => {
  if (!req.file) return res.send('No file uploaded.');

  const filename = Date.now() + '.jpg';

  try {
    // Small: 100x100
    await sharp(req.file.buffer).resize(100, 100).toFile(`uploads/small/${filename}`);
    // Medium: 400x400
    await sharp(req.file.buffer).resize(400, 400).toFile(`uploads/medium/${filename}`);
    // Large: 800x800
    await sharp(req.file.buffer).resize(800, 800).toFile(`uploads/large/${filename}`);

    res.send(`Image saved in 3 sizes as: ${filename}`);
  } catch (err) {
    res.status(500).send('Error resizing image: ' + err.message);
  }
});

app.listen(3000, () => console.log('Server on port 3000'));

