import { useState } from 'react';

function App() {
  const [text, setText] = useState('LJ University');
  const [color, setColor] = useState('red');
  const [visible, setVisible] = useState(true);
  const [btnLabel, setBtnLabel] = useState('Hide');

  const changeText = () => {
    setText(prev => prev === 'LJ University' ? 'Welcome students' : 'LJ University');
  };

  const changeColor = () => {
    setColor(prev => prev === 'red' ? 'blue' : 'red');
  };

  const toggleVisibility = () => {
    if (visible) {
      setVisible(false);
      setBtnLabel('Show');
    } else {
      setVisible(true);
      setBtnLabel('Hide');
    }
  };

  return (
    <div>
      <h1 style={{ color: color }}>{text}</h1>
      {visible && <h2>React Js Hooks</h2>}
      <button onClick={changeText}>Change Text</button>
      <button onDoubleClick={changeColor}>Change Color</button>
      <button onClick={toggleVisibility}>{btnLabel}</button>
    </div>
  );
}

export default App;

