import { useState, useEffect } from 'react';

function App() {
  const [num1, setNum1] = useState('');
  const [num2, setNum2] = useState('');
  const [result, setResult] = useState(null);
  const [operation, setOperation] = useState('');
  const [addCount, setAddCount] = useState(0);

  // useEffect triggers alert every time addCount changes (addition clicked)
  useEffect(() => {
    if (addCount > 0) alert('Addition button clicked!');
  }, [addCount]);

  const add = () => {
    setResult(parseFloat(num1) + parseFloat(num2));
    setOperation('Addition');
    setAddCount(prev => prev + 1);
  };

  const subtract = () => {
    setResult(parseFloat(num1) - parseFloat(num2));
    setOperation('Subtraction');
  };

  return (
    <div style={{ padding: '20px' }}>
      <h2>Calculator</h2>
      <input type="number" placeholder="Number 1" value={num1} onChange={e => setNum1(e.target.value)} />
      <input type="number" placeholder="Number 2" value={num2} onChange={e => setNum2(e.target.value)} />
      <br/><br/>
      <button onClick={add}>Addition</button>
      <button onClick={subtract}>Subtraction</button>
      {result !== null && <h3>{operation}: {result}</h3>}
    </div>
  );
}
