import { useReducer } from 'react';

const reducer = (state, action) => {
  switch (action.type) {
    case 'add':
      return { quantity: state.quantity + 1 };
    case 'remove':
      return { quantity: Math.max(0, state.quantity - 1) }; // Never go below 0
    default:
      return state;
  }
};

function App() {
  const [state, dispatch] = useReducer(reducer, { quantity: 0 });

  return (
    <div style={{ textAlign: 'center', padding: '30px' }}>
      <h2>Product Quantity Manager</h2>
      <h1>Quantity: {state.quantity}</h1>
      <button onClick={() => dispatch({ type: 'add' })}>Add Item</button>
      <button onClick={() => dispatch({ type: 'remove' })} disabled={state.quantity === 0}>
        Remove Item
      </button>
    </div>
  );
}

export default App;

