// (1) Text index for substring search on name
// Create text index on name field
db.student.createIndex({ name: "text" })

// Query using $text search for "BBB"
db.student.find({ $text: { $search: "BBB" } }).explain("executionStats")
// Matches: {name:"BBB",age:20} and {name:"AAA BBB",age:10}
// Predicted: nReturned=2, docsExamined=2 (IXSCAN via text index)

// Alternative using $regex (no text index needed):
db.student.createIndex({ name: 1 })
db.student.find({ name: { $regex: /BBB/ } }).explain("executionStats")
// nReturned=2 (BBB and AAA BBB match)
// docsExamined=2 with index

// (2) Create partial index on age > 15 (subset index)
db.student.createIndex(
  { age: 1 },
  { partialFilterExpression: { age: { $gt: 15 } } }
)

// Query for age > 15
db.student.find({ age: { $gt: 15 } }).explain("executionStats")
// With partial index: only docs with age>15 are indexed (DDD:32, BBB:20)
// So: nReturned=2, docsExamined=2 — even though 3 total docs exist
// stage = IXSCAN

