import React, { useState } from 'react';
import axios from 'axios';

function App() {
  const [form, setForm] = useState({ name: '', rollno: '', totalmarks: '' });
  const [msg, setMsg] = useState('');

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = () => {
    axios.post('http://localhost:5000/add', form)
      .then(res => setMsg(res.data.msg))
      .catch(err => setMsg('Error: ' + err.message));
  };

  return (
    <div style={{ textAlign: 'center', marginTop: 40 }}>
      <h2>Student Form</h2>
      <input type="text" name="name" placeholder="Name"
        value={form.name} onChange={handleChange} /><br/><br/>
      <input type="number" name="rollno" placeholder="Roll No"
        value={form.rollno} onChange={handleChange} /><br/><br/>
      <input type="number" name="totalmarks" placeholder="Total Marks"
        value={form.totalmarks} onChange={handleChange} /><br/><br/>
      <button onClick={handleSubmit}>Submit</button>
      {msg && <p>{msg}</p>}
    </div>
  );
}

export default App;

