import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [form, setForm] = useState({ name: '', empId: '', salary: '', department: '' });
  const [employees, setEmployees] = useState([]);

  const fetchEmployees = () => {
    axios.get('http://localhost:5000/all')
      .then(res => setEmployees(res.data));
  };

  useEffect(() => { fetchEmployees(); }, []);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = () => {
    axios.post('http://localhost:5000/add', form)
      .then(() => { fetchEmployees(); setForm({ name:'', empId:'', salary:'', department:'' }); })
      .catch(err => console.log(err));
  };

  return (
    <div style={{ padding: 20 }}>
      <h2>Employee Form</h2>
      <input name="name" placeholder="Name" value={form.name} onChange={handleChange} /><br/><br/>
      <input name="empId" type="number" placeholder="Emp ID" value={form.empId} onChange={handleChange} /><br/><br/>
      <input name="salary" type="number" placeholder="Salary" value={form.salary} onChange={handleChange} /><br/><br/>
      <input name="department" placeholder="Department" value={form.department} onChange={handleChange} /><br/><br/>
      <button onClick={handleSubmit}>Submit</button>

      <h3>Saved Employees:</h3>
      <table border="1">
        <thead><tr><th>Name</th><th>Emp ID</th><th>Salary</th><th>Department</th></tr></thead>
        <tbody>
          {employees.map((e, i) => (
            <tr key={i}><td>{e.name}</td><td>{e.empId}</td><td>{e.salary}</td><td>{e.department}</td></tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default App;

