const express = require('express');
const mongoose = require('mongoose');
const cors = require('cors');

const app = express();
app.use(cors());
app.use(express.json());

mongoose.connect('mongodb://localhost:27017/courseDB', {
  useNewUrlParser: true,
  useUnifiedTopology: true
}).then(() => console.log('Connected to courseDB'));

const enrollSchema = new mongoose.Schema({
  studentName: String,
  courseName: String,
  email: { type: String, unique: true }  // unique prevents duplicate enrollments
});
const Enrollment = mongoose.model('Enrollment', enrollSchema);

app.post('/enroll', async (req, res) => {
  try {
    // Check for duplicate: same email + same course
    const existing = await Enrollment.findOne({
      email: req.body.email,
      courseName: req.body.courseName
    });
    if (existing) {
      return res.status(400).json({ error: 'You are already enrolled in this course!' });
    }
    const newEnroll = new Enrollment(req.body);
    await newEnroll.save();
    res.json({ message: 'Enrolled successfully!' });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

app.listen(5000);

// ========== FRONTEND: src/App.js ==========
import React, { useState } from 'react';
import axios from 'axios';

function App() {
  const [form, setForm] = useState({ studentName: '', courseName: '', email: '' });
  const [msg, setMsg] = useState('');
  const [isError, setIsError] = useState(false);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = () => {
    axios.post('http://localhost:5000/enroll', form)
      .then(res => { setMsg(res.data.message); setIsError(false); })
      .catch(err => { setMsg(err.response.data.error); setIsError(true); });
  };

  return (
    <div style={{ padding: 30 }}>
      <h2>Course Enrollment</h2>
      <input name="studentName" placeholder="Student Name" value={form.studentName} onChange={handleChange} /><br/><br/>
      <input name="courseName" placeholder="Course Name" value={form.courseName} onChange={handleChange} /><br/><br/>
      <input name="email" type="email" placeholder="Email" value={form.email} onChange={handleChange} /><br/><br/>
      <button onClick={handleSubmit}>Enroll</button>
      {msg && <p style={{ color: isError ? 'red' : 'green' }}>{msg}</p>}
    </div>
  );
}

export default App;

